jokeButton.addEventListener('click', () => {
    // Get a random joke from the array
    const randomJoke = jokes[Math.floor(Math.random() * jokes.length)];

    // Display the joke
    jokeParagraph.textContent = `Joke ${randomJoke.id}: ${randomJoke.joke}`;
